(() => {
  const searchUrl = `/search?q=${encodeURIComponent('${{ args.query }}')}&f=top`;
  window.history.pushState({}, '', searchUrl);
  window.dispatchEvent(new PopStateEvent('popstate', { state: {} }));
})()

(() => {
  const results = [];
  const seen = new Set();
  const tweets = document.querySelectorAll('[data-testid="tweet"]');

  tweets.forEach(tweet => {
    try {
      const link = tweet.querySelector('a[href*="/status/"]');
      if (!link) return;
      const match = link.href.match(/\/status\/(\d+)/);
      if (!match) return;
      const id = match[1];
      if (seen.has(id)) return;
      seen.add(id);

      const author = tweet.querySelector('[data-testid="User-Name"] a')?.textContent?.replace('@', '') || 'unknown';
      const textEl = tweet.querySelector('[data-testid="tweetText"]');
      const text = textEl ? textEl.textContent : '';
      const url = `https://x.com/i/status/${id}`;

      results.push({ id, author, text, url });
    } catch (e) {}
  });

  return results;
})()
